/**
 * Repairs malformed material metadata in GLB files generated by 3D tools.
 *
 * Responsibility: rewrites only the GLB JSON chunk so `materials` is a valid
 * glTF array and existing base-color, normal, and metallic-roughness texture
 * bindings can be consumed by Three.js. It does not alter binary image payloads,
 * geometry, animation, skeletons, or morph targets.
 *
 * Side effects: reads the input GLB from disk and writes a repaired GLB to the
 * output path. No network, database, or user-profile I/O is performed.
 *
 * Key dependencies and constraints: expects glTF 2.0 binary GLB with a JSON
 * chunk. The BIN chunk is copied byte-for-byte. JSON and GLB chunk lengths are
 * padded to four-byte alignment as required by the GLB container format.
 */
import { readFileSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath, pathToFileURL } from 'node:url';

const JSON_CHUNK_TYPE = 0x4e4f534a;
const BIN_CHUNK_TYPE = 0x004e4942;
const GLB_MAGIC = 0x46546c67;
const GLB_VERSION = 2;

/**
 * Runs the command-line repair workflow.
 *
 * Inputs: `process.argv[2]` is the input GLB path; `process.argv[3]` is the
 * output GLB path. When omitted, paths default to `public/assets/pet.glb`.
 * Returns: nothing.
 * Errors: throws for invalid GLB containers or missing JSON chunks; Node prints
 * the error and exits non-zero.
 * Side effects: writes the repaired GLB file.
 */
function main() {
  const projectRoot = resolve(dirname(fileURLToPath(import.meta.url)), '..');
  const inputPath = resolve(projectRoot, process.argv[2] ?? 'public/assets/pet.glb');
  const outputPath = resolve(projectRoot, process.argv[3] ?? process.argv[2] ?? 'public/assets/pet.glb');
  const repaired = repairGlbMaterialMetadata(readFileSync(inputPath));

  writeFileSync(outputPath, repaired);
  console.log(`Repaired GLB material metadata: ${inputPath} -> ${outputPath}`);
}

/**
 * Repairs material metadata inside a GLB buffer.
 *
 * Inputs: `input` is the complete binary GLB file content.
 * Returns: a new Buffer containing the repaired GLB.
 * Errors: throws when magic/version/chunks are invalid.
 * Side effects: none.
 */
export function repairGlbMaterialMetadata(input) {
  const chunks = readGlbChunks(input);
  const jsonChunk = chunks.find((chunk) => chunk.type === JSON_CHUNK_TYPE);

  if (!jsonChunk) {
    throw new Error('GLB JSON chunk was not found.');
  }

  const json = JSON.parse(stripJsonPadding(jsonChunk.data).toString('utf8'));
  repairMaterialJson(json);

  const repairedJsonChunk = {
    type: JSON_CHUNK_TYPE,
    data: padJsonBuffer(Buffer.from(JSON.stringify(json), 'utf8'))
  };
  const repairedChunks = chunks.map((chunk) =>
    chunk === jsonChunk ? repairedJsonChunk : { type: chunk.type, data: padBinaryBuffer(chunk.data) }
  );

  return writeGlbChunks(repairedChunks);
}

/**
 * Normalizes material fields in glTF JSON.
 *
 * Inputs: mutable parsed glTF JSON object.
 * Returns: the same object for convenience.
 * Errors: does not throw for missing optional fields.
 * Side effects: mutates `json.materials` and mesh primitive material indices.
 */
export function repairMaterialJson(json) {
  if (json.materials && !Array.isArray(json.materials)) {
    json.materials = [json.materials];
  }

  if (!json.materials || json.materials.length === 0) {
    json.materials = [createDefaultMaterial()];
  }

  json.materials = json.materials.map((material) => sanitizeMaterial(material));

  for (const mesh of json.meshes ?? []) {
    for (const primitive of mesh.primitives ?? []) {
      if (typeof primitive.material !== 'number' || primitive.material >= json.materials.length) {
        primitive.material = 0;
      }
    }
  }

  return json;
}

/**
 * Creates a fallback material binding to common generated texture indices.
 *
 * Inputs: none.
 * Returns: a glTF material object using texture 1 as base color, texture 0 as
 * normal, and texture 2 as metallic-roughness.
 * Errors: does not throw.
 * Side effects: none.
 */
function createDefaultMaterial() {
  return {
    name: 'RepairedMaterial',
    doubleSided: true,
    normalTexture: { index: 0 },
    pbrMetallicRoughness: {
      baseColorTexture: { index: 1 },
      metallicRoughnessTexture: { index: 2 },
      metallicFactor: 0.0,
      roughnessFactor: 0.85
    }
  };
}

/**
 * Removes invalid material extension fields while preserving PBR texture links.
 *
 * Inputs: raw material object from glTF JSON.
 * Returns: sanitized material object.
 * Errors: does not throw.
 * Side effects: none; returns a shallow copy.
 */
function sanitizeMaterial(material) {
  const sanitized = {
    ...material,
    doubleSided: material.doubleSided ?? true,
    pbrMetallicRoughness: {
      ...material.pbrMetallicRoughness,
      metallicFactor: material.pbrMetallicRoughness?.metallicFactor ?? 0.0,
      roughnessFactor: material.pbrMetallicRoughness?.roughnessFactor ?? 0.85
    }
  };

  if (sanitized.extensions?.KHR_materials_specular) {
    delete sanitized.extensions.KHR_materials_specular;
  }

  if (sanitized.extensions && Object.keys(sanitized.extensions).length === 0) {
    delete sanitized.extensions;
  }

  return sanitized;
}

/**
 * Reads chunk metadata and payloads from a GLB buffer.
 *
 * Inputs: complete GLB buffer.
 * Returns: ordered chunks with numeric type and Buffer data.
 * Errors: throws for invalid header values.
 * Side effects: none.
 */
function readGlbChunks(input) {
  if (input.readUInt32LE(0) !== GLB_MAGIC || input.readUInt32LE(4) !== GLB_VERSION) {
    throw new Error('Input is not a glTF 2.0 GLB file.');
  }

  const chunks = [];
  const declaredLength = input.readUInt32LE(8);
  let offset = 12;

  while (offset < declaredLength) {
    const length = input.readUInt32LE(offset);
    const type = input.readUInt32LE(offset + 4);
    chunks.push({
      type,
      data: input.subarray(offset + 8, offset + 8 + length)
    });
    offset += 8 + length;
  }

  return chunks;
}

/**
 * Writes GLB chunks into a complete GLB buffer.
 *
 * Inputs: ordered chunks with padded data.
 * Returns: complete GLB buffer.
 * Errors: does not throw for valid chunk data.
 * Side effects: none.
 */
function writeGlbChunks(chunks) {
  const totalLength = 12 + chunks.reduce((sum, chunk) => sum + 8 + chunk.data.length, 0);
  const output = Buffer.alloc(totalLength);
  let offset = 12;

  output.writeUInt32LE(GLB_MAGIC, 0);
  output.writeUInt32LE(GLB_VERSION, 4);
  output.writeUInt32LE(totalLength, 8);

  for (const chunk of chunks) {
    output.writeUInt32LE(chunk.data.length, offset);
    output.writeUInt32LE(chunk.type, offset + 4);
    chunk.data.copy(output, offset + 8);
    offset += 8 + chunk.data.length;
  }

  return output;
}

/**
 * Removes JSON padding from a GLB JSON chunk.
 *
 * Inputs: JSON chunk buffer.
 * Returns: a buffer slice without trailing NUL or space padding.
 * Errors: does not throw.
 * Side effects: none.
 */
function stripJsonPadding(buffer) {
  let end = buffer.length;

  while (end > 0 && (buffer[end - 1] === 0x00 || buffer[end - 1] === 0x20)) {
    end -= 1;
  }

  return buffer.subarray(0, end);
}

/**
 * Pads JSON chunk data to GLB four-byte alignment.
 *
 * Inputs: unpadded JSON buffer.
 * Returns: padded buffer using ASCII spaces.
 * Errors: does not throw.
 * Side effects: none.
 */
function padJsonBuffer(buffer) {
  return padBuffer(buffer, 0x20);
}

/**
 * Pads binary chunk data to GLB four-byte alignment.
 *
 * Inputs: binary payload buffer.
 * Returns: padded buffer using NUL bytes.
 * Errors: does not throw.
 * Side effects: none.
 */
function padBinaryBuffer(buffer) {
  return padBuffer(buffer, 0x00);
}

/**
 * Pads a buffer to four-byte alignment with a selected byte.
 *
 * Inputs: source buffer and pad byte.
 * Returns: original buffer if already aligned, otherwise a new padded buffer.
 * Errors: does not throw.
 * Side effects: none.
 */
function padBuffer(buffer, padByte) {
  const remainder = buffer.length % 4;

  if (remainder === 0) {
    return Buffer.from(buffer);
  }

  const output = Buffer.alloc(buffer.length + (4 - remainder), padByte);
  buffer.copy(output);
  return output;
}

if (import.meta.url === pathToFileURL(process.argv[1]).href) {
  main();
}
